export function getAssetsByCategory(category: string): AssetInfo[] {
  return ASSET_CATALOG.flatMap(pack => pack.assets.filter(a => a.category === category));
}

export function getAssetsBySubcategory(subcategory: string): AssetInfo[] {
  return ASSET_CATALOG.flatMap(pack => pack.assets.filter(a => a.subcategory === subcategory));
}

export function searchAssets(query: string): AssetInfo[] {
  const lowerQuery = query.toLowerCase();
  return ASSET_CATALOG.flatMap(pack => 
    pack.assets.filter(a => 
      a.name.toLowerCase().includes(lowerQuery) ||
      a.category.toLowerCase().includes(lowerQuery) ||
      a.subcategory?.toLowerCase().includes(lowerQuery) ||
      a.description?.toLowerCase().includes(lowerQuery)
    )
  );
}

export function getAnimatedAssets(): AssetInfo[] {
  return ASSET_CATALOG.flatMap(pack => pack.assets.filter(a => a.animations && a.animations.length > 0));
}

export function getAllAssetPaths(): string[] {
  return ASSET_CATALOG.flatMap(pack => pack.assets.map(a => a.path));
}
